+    if (Array.isArray(variant.enum)) {
+      const { enumValues, nullable: enumNullable } = normalizeEnumValues(
+        variant.enum,
+      );
+      values.push(...enumValues);
+      if (enumNullable) nullable = true;
+      continue;
+    }
+    if ("const" in variant) {
+      if (variant.const === null || variant.const === undefined) {
+        nullable = true;
+        continue;
